import { ReActAgent } from 'llamaindex';

interface CostMetrics {
  stepCount: number;
  tokenUsage: number;
}

const stepTracker = (agent: ReActAgent) => {
  return async (query: string) => {
    const metrics: CostMetrics = { stepCount: 0, tokenUsage: 0 };

    const wrappedAgent = {
      chat: async (input: string) => {
        metrics.stepCount++;
        const result = await agent.chat(input);
        metrics.tokenUsage += result.message.content.length / 4; // ~4 chars per token

        if (metrics.stepCount > 5) {
          throw new Error(`Excessive steps: ${metrics.stepCount}`);
        }

        return result;
      }
    };

    return wrappedAgent.chat(query);
  };
};
